var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으아아아악!!","JPN":"うわああああ！!","ENG":"Aaaack!!","TWN":"啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"죽어!! 죽어버려!! 이 빌어먹을 개자식들아!!","JPN":"死ね！！　死んでしまえ！！　このクソ野郎ども！！","ENG":"Die!! DIE!! You creepy bastards!!","TWN":"去死吧！全都去死！！你們這些畜生！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"정신차려 신참!! 튀어나가지 말고 대형을 유지해!!","JPN":"落ち着け、新米！！　飛び出るな、隊形を維持しろ！！","ENG":"Get a hold of yourself, rookie!! Stop falling out of line and keep formation!!","TWN":"菜鳥，你冷靜點！不要亂跑，要維持隊形！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"진정? 방금 보셨지 않습니까, 중대장님!!","JPN":"落ち着く？　今の見ませんでしたか、中隊長！！","ENG":"What? But sir! Didn't you see what just happened?!","TWN":"冷靜？中隊長，你剛沒看到嗎！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"저 녀석들이 눈 앞에서 글렌 녀석을 갈갈이 찢어버렸다고요!!","JPN":"あいつらが目の前でグレンのやつを八つ裂きにしやがったんですよ！！","ENG":"Those scum tore up Glen right in front of our eyes!!","TWN":"那些畜生就在我們的眼前，將格倫那小子給分屍欸！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"제길, 누가 그걸 모르나!? 죽기 싫으면 정신 차리고 조준 사격해!!","JPN":"くっそ、そんなのわかっている！！　死にたくなければしっかり照準射撃しろ！！","ENG":"Dammit. Don't you think I know? If you don't wanna die, stay sharp and aim before you shoot!!","TWN":"該死的！我眼睛又沒瞎！不想死的話，就冷靜下來瞄準射擊！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"제기랄…… 성황청은 분명 이번 성무가 대인 작전이라고 했어요.","JPN":"ちくしょう……聖皇庁は確かに今回の聖務は対人作戦だって言ってたんです。","ENG":"Damn...! The Holy Curia clearly said that this sacred mission was gonna be an anti-personnel operation!","TWN":"該死的……聖皇廳明明說這次作戰的對象是人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그런데 저건 뭡니까? 침식체잖아요!! 게다가 저렇게 쏟아지는데!!","JPN":"なのにあれは何ですか？　侵食体じゃないですか！！　しかもあんなに大量の！！","ENG":"But do you see that?! Those are C.O.s!! And they just keep pouring out!!","TWN":"搞什麼鬼？根本就是侵蝕體！！而且數量還那麼多！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"성황청이 우릴 속였어요! 우린 버려진 겁니다! 여기서 다 죽을 거라고요!!","JPN":"聖皇庁が俺たちを騙したんです！　俺たちは捨てられたんですよ！　みんなここで死ぬんです！！","ENG":"The Holy Curia deceived us! They threw us under the bus! We're all gonna die out here!!","TWN":"聖皇廳騙我們！竟然擺我們一道！我們全都會死在這裡！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이 새끼가 말 다했어? 헌금 받아먹고 사는 주제에 그런 말이 입에서 나와!?","JPN":"この野郎、なんだと？　献金で食わせてもらってるくせに、なんてことを言うんだ！？","ENG":"Shut it, will you?! You got a big mouth for someone who lives off of church donations!","TWN":"你這臭小子說完沒？靠人家養活還敢說那種話！？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"두 분 다 그만하세요!!","JPN":"お二人とも、おやめください！！","ENG":"Please stop it, the both of you!!","TWN":"都別再說了！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"수녀님!?","JPN":"シスター！？","ENG":"Sister?!","TWN":"修女！？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"헤밍턴 형제님 말씀이 옳아요. 이번 성무는 어디서부터인가 어긋났어요.","JPN":"ハミントン兄弟のおっしゃるとおりですわ。今回の聖務はどこか食い違いがあるようです。","ENG":"Brother Hammington is right. Something isn’t right about this sacred mission.","TWN":"海明頓弟兄說的沒錯，這次的聖務確實哪裡不對勁。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"침식체들의 움직임도 심상치 않아요.","JPN":"侵食体の動きも尋常ではありません。","ENG":"Even the C.O.s are behaving strangely.","TWN":"侵蝕體的行動也不太正常。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"습격과 도주를 거듭하면서 우리를 숲 속 깊은 곳으로 몰아넣고 있어요. 굉장히 교활하고, 치밀하게요.","JPN":"襲撃と逃走をくり返しながら、私たちを森の奥深くに追い込んでいます。とても狡猾かつ細緻に。","ENG":"They are using cunning tactics to ambush us and then retreat, ultimately driving us deeper into the forest.","TWN":"他們一下偷襲，一下又逃跑，就是想把我們逼到森林深處，行為非常地狡猾而且有組織性。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"무언가가 침식체를 조종하고 있다는 말씀이십니까?","JPN":"何者かが侵食体を操っているということですか？","ENG":"Are you saying that someone, or something, is controlling those C.O.s?","TWN":"意思是有人在控制那些侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"확신할 수 없지만……","JPN":"確信は持てませんけど……","ENG":"I can’t be certain, but...","TWN":"我也無法肯定……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"퇴각 준비를 해 주세요. 이번 성무는 실패입니다.","JPN":"退却の準備をしてください。今回の聖務は失敗ですわ。","ENG":"Prepare to retreat. This mission is a failure.","TWN":"大家準備撤退，這次的聖務失敗。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"하지만 수녀님, 조금만 더 가면 사교도들의 마을에 도착합니다.","JPN":"ですがシスター、もう少し行けば邪教徒の村です。","ENG":"But Sister, if we go a little further we'll reach the cultist village.","TWN":"不過修女，再往前一點就是邪教徒的村莊，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"성무의 중책을 맡고 여기서 발길을 돌리는 건……!","JPN":"聖務の重責を負いながらここで引き返すのは……！","ENG":"If we were to abandon the sacred mission and turn around now─!","TWN":"我們身負聖務的重責大任，就這樣半途而廢的話……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMPANY_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"중대장님!! 놈들입니다! 땅속에서 솟구치고 있어요!","JPN":"中隊長！！　やつらです！　地下から湧き出てきます！","ENG":"Sir!! It's them! They're coming out of the ground!","TWN":"中隊長！！是侵蝕體！他們從地上冒出來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMPANY_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으아아아악!! 살려 줘어어!","JPN":"うわああああ！!　助けてくれええ！","ENG":"Aaaagh!! Help!","TWN":"啊啊啊啊！！救我！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……이미 발을 빼기에는 늦었군요.","JPN":"……手を引くには遅すぎましたね。","ENG":"It seems like it's too late to turn back now.","TWN":"……來不及撤了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"중대장님, 대형을 갖춰주세요! 제 기도가 모든 분들께 닿을 수 있도록!","JPN":"中隊長、隊形を整えてください！　私の祈りがすべての方々に届くように！","ENG":"Captain, maintain formation so that my prayers will reach everyone!","TWN":"中隊長，請你維持隊形！讓我的祈禱可以達到每個人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"제기랄……! 알겠습니다!","JPN":"ちくしょう……！　わかりました！","ENG":"Dammit...! On it!","TWN":"可惡……！收到！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"다들 대형을 갖춰! 수녀님만큼은 반드시 지켜드려야 한다!","JPN":"総員、隊形を整えろ！　シスターだけは絶対にお守りするんだ！","ENG":"Men, assume formation! Protect Sister Nelson at all cost!","TWN":"大家維持隊形！至少要保住修女！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"결국 그 시커먼 나무 뿌리처럼 생긴 놈들이 우리 대원들을 전부 낚아채서 숲 속으로 끌고 가 버렸지.","JPN":"結局その真っ黒な木の根のような形をしたやつらに隊員は全員捕らえられて、森の奥に連れていかれた。","ENG":"Those root-like monsters snatched my entire team and dragged them into the forest.","TWN":"結果那些長得像漆黑樹根的傢伙，就把隊員全都拖進森林深處裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"한 명씩, 차례차례…… 겁에 질린 우리들을 농락하듯 말이야…….","JPN":"一人ずつ、順番に……怯えている俺らをもてあそぶようにな……","ENG":"One after the other... As if they were enjoying our terror...","TWN":"一個接著一個……好像在玩弄驚恐的我們一樣……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이상한 대목이로군요.","JPN":"おかしな一節ですね。","ENG":"What a strange occurrence.","TWN":"這個章節有點不合理。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그림자 같은 특별한 케이스가 아닌 이상, 보통의 침식체에게는 지성이 없습니다.","JPN":"シャドウのような特殊ケースでないかぎり、普通の侵食体に知性はありません。","ENG":"C.O.s usually lack intelligence unless they are a special case like Shadows.","TWN":"他們又不是暗影，普通的侵蝕體是沒有思想的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그저 인간에 대한 무차별적인 적개심을 보일 뿐이죠.","JPN":"ただ人間への無差別な敵対心を見せるだけです。","ENG":"They simply exhibit indiscriminate hostility toward humans.","TWN":"他們只會單純地對人類產生攻擊性。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"한 명씩 농락하듯이 당신들을 제거했다는 말은 맥락에 안 맞습니다만.","JPN":"一人ずつもてあそぶように取り除いたというのは筋が通りませんが。","ENG":"So what you are saying about how they seemed to \\"enjoy\\" killing your crew is illogical.","TWN":"你說他們好像在玩弄你們一樣，一個接一個把你們除掉，這段話不太合邏輯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"나도 알고 있어. 하지만…….","JPN":"俺も知ってる。でも……","ENG":"I know that. But...","TWN":"我也知道，可是……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그 녀석들은\xA0 마치 처음부터 분명한 목적이 있는 것처럼 움직였어.","JPN":"あいつらはまるで最初から確かな目的があるように動いてたんだ。","ENG":"They behaved as if they had a clear goal from the start.","TWN":"他們似乎從一開始就是有帶有目的性在行動的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"목적?","JPN":"目的？","ENG":"A goal?","TWN":"目的性？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그래. 어쩌면……","JPN":"そう。もしかしたら……","ENG":"Yes... Perhaps...","TWN":"對，或許……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"어쩌면…… 내가 살아남을 수 있었던 이유는……","JPN":"もしかしたら……俺が生き残ることができた理由は……","ENG":"Perhaps... The only reason I was able to survive is...","TWN":"或許……我之所以能活下來……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"허억!","JPN":"はっ！","ENG":"*Gasp...!*","TWN":"嚇！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"살았나……!? 어, 어떻게……!?","JPN":"生きてる……！？　な、なんで……！？","ENG":"I-I'm alive...?! B-but how...?!","TWN":"我沒死……！？怎麼會……！？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"다른 중대원들은…….","JPN":"他の中隊員たちは……","ENG":"The others...","TWN":"其他人呢……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"윽……. 하아…….","JPN":"うっ……はあ……","ENG":"Ngh... *Huff...*","TWN":"唔……呼……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"수, 수녀님? 설마 절 감싸 주신 겁니까……?","JPN":"し、シスター？　まさか俺を庇ってくださったのですか……？","ENG":"S-Sister Nelson? Are you the one who saved me...?","TWN":"修…修女？剛剛是你保護我的嗎……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"어째서 도망치지 않으시고, 저 같은 것 때문에…….","JPN":"どうしてお逃げにならずに、俺なんかのために……","ENG":"Why did you stay when you could've run...?","TWN":"你為什麼不逃，幹嘛要保護我這種人……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OCTOPUS3_VATICAN_NULL_NULL","text":{"KOREA":"<color=#ff3636>성찬</color>을 준비하<color=#ff3636>라. 새로운 날</color>이 당도하<b>리</b>니.\xA0","JPN":"<color=#ff3636>聖餐</color>を用意し<color=#ff3636>ろ。新しい日</color>が到来<b>す</b>る。\xA0","ENG":"Prepare <color=#ff3636>the fea</color>st. A new da<color=#ff3636>wn is</color> com<b>in</b>g.\xA0","TWN":"預備<color=#ff3636>盛宴</color><color=#ff3636>吧。新天</color>已來<b>到</b>。\xA0"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으, 으아아아악……!!","JPN":"う、うわああああ……！!","ENG":"A-AAAACK!","TWN":"啊啊啊啊……！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"수녀님! 정신 차리세요! 도망치셔야 합니다!","JPN":"シスター！　お気を確かに！　お逃げください！","ENG":"Sister! Wake up! We have to run away!","TWN":"修女！你振作一點！我們要快點逃！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으윽……! 제기랄, 다리가 부러져서…… 움직일 수가……!","JPN":"ううっ……！　クソ、足が折れて……動けない……！","ENG":"Ngh...! Dammit! My leg... It's broken...!","TWN":"呃……！該死，我的腿斷了……沒辦法動……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"뭐, 뭐지? 왜 공격하지 않는 거야……?","JPN":"な、何だ？　なんで攻撃しないんだ……？","ENG":"H-huh? Why aren't they attacking...?","TWN":"怎…怎麼回事？為何不攻擊我們……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"자, 잠깐……! 수녀님을 데려가서 어쩌려는 거냐!? 그만둬!!","JPN":"ま、待て……！　シスターを連れて行ってどうするつもりだ！？　やめろ！！","ENG":"W-wait..! Where are you taking Sister Nelson?! No!!","TWN":"等等……！我把修女帶走又能怎麼辦！？不管啦！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"히…… 히이익! 사, 살려줘. 내, 내가 잘못했어!","JPN":"ひ……ひいいっ！　た、助けてくれ。お、俺が悪かった！","ENG":"E-eeeek! D-don't kill me! P-please forgive me!","TWN":"嗚……嗚嗚嗚！對…對不起，拜託別殺我！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그 나무 뿌리 같은 침식체들은 수녀님만 노리고 있었어. 나 따위는 안중에도 없었지.","JPN":"あの木の根のような侵食体はシスターだけを狙ってたんだ。俺なんかは眼中にもなかった。","ENG":"Those root-like C.O.s were after Sister Nelson and only her.","TWN":"像樹根的侵蝕體目標是修女，根本沒把我放眼裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"놈들의 목표는…… 처음부터 수녀님이었던 거야.","JPN":"やつらの目標は……最初からシスターだったんだよ。","ENG":"Their goal was... to capture her.","TWN":"他們的目標……從一開始就是修女。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇군요. 역시 시스터 넬슨은 그런 경위로…….","JPN":"そうですか。やはりシスターネルソンはそういった経緯で……","ENG":"I see. So that is how Sister Nelson ended up there...","TWN":"原來尼爾森修女是因為這樣……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"당신, 사람을 찾고 있다고 했지?","JPN":"あんた、人を探してるって言ってたな。","ENG":"Hey you. You said you were looking for someone.","TWN":"你剛你說在找人是吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그래, 나는 넬슨 수녀님을 침식체에게 팔아 넘기고 추하게 살아남았어.","JPN":"そうだ、俺はシスターネルソンを侵食体に売って、みすぼらしく生き残ったんだ。","ENG":"That's right. I survived because I let them take Sister Nelson.","TWN":"沒錯，就是我出賣尼爾森修女，還厚顏無恥地活下來！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"이게…… 아마 당신이 듣고 싶었던 말일 거야, 그렇지?","JPN":"これが……たぶんあんたが聞きたかった話なんだろ、違うか？","ENG":"This... is what you wanted to hear, isn't it?","TWN":"這……就是你想聽到的話吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"비겁한 변명인 건 알아.","JPN":"卑怯な言いわけだってことはわかってる。","ENG":"I know it's a lousy excuse.","TWN":"雖然聽起來很像是在狡辯，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"하, 하지만 나도 어쩔 수 없었다고……!!","JPN":"で、でも俺も仕方なかったんだよ……！！","ENG":"B-but I had no other choice...!!","TWN":"但，我是真的沒辦法……！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"손도, 발도 얼어붙어서 꼼작도 할 수 없었어!! 난 당신들 같은 초인이 아니니까!","JPN":"手も足も凍り付いてビクともしなかったんだ！！　俺はあんたたちのような超人じゃないから！","ENG":"My whole body was paralyzed with fear! I'm not superhuman like you!","TWN":"我的手，我的腳都動彈不得！！我又不像你一樣是超人！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그렇게 상냥하던 수녀님을……. 수녀님은 나를 구해 주시기까지 했는데……!! 흐흑……!","JPN":"あんなに優しかったシスターを……シスターは俺を助けてくださったのに……！！　ううっ……！","ENG":"That kind nun... She saved me, but...! *Sniffle...!*","TWN":"修女那麼善良……她甚至還捨命救我……！！嗚嗚……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"이제…… 나는 어떻게 되는 거지?","JPN":"これから……俺はどうなるんだ？","ENG":"What... What's going to happen to me now?","TWN":"我……之後會怎麼樣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"성황청에 날 고발할 건가? 아니면…… 지금 이 자리에서 날 심판하려는 건가?","JPN":"聖皇庁に告発するのか？　それとも……今この場で審判するつもりなのか？","ENG":"Are you going to report it to the Holy Curia? Or... Are you here right now to kill me yourself?","TWN":"你要向聖皇廳舉發我嗎？還是……就地正法？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이…… 정정해드리죠.","JPN":"喜んで……訂正いたします。","ENG":"I would be... more than happy to rephrase.","TWN":"我要……更正一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말씀드렸다시피 저는 성황청의 입장을 대변해서 온 것이 아닙니다.","JPN":"先ほどお話ししたとおり、私は聖皇庁を代弁するために来たわけではありません。","ENG":"As I previously stated. I am not here on behalf of the Holy Curia.","TWN":"我剛才也說過，我不是代表聖皇廳而來的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신에게 책임을 물을 생각도, 그럴 자격도 없고요.","JPN":"あなたに責任を問うつもりも、その資格もないのです。","ENG":"I have no intention of holding you accountable for your actions, nor do I have the authority to do so.","TWN":"我沒資格，也不打算向你究責。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐라고……?","JPN":"な、何だと……？","ENG":"W-what...?","TWN":"什…什麼意思……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그게 무슨 소리야? 넬슨 수녀님 때문에 날 찾아온 거 아니었어?","JPN":"どういうことだ？　シスターネルソンのことで訪ねてきたんじゃないのか？","ENG":"What do you mean? Didn't you come here because of Sister Nelson?","TWN":"你在說什麼？你來找我不是因為尼爾森修女的事嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 제가 찾고 있는 사람은 다른 사람입니다.","JPN":"いいえ。私が探している人は別の人です。","ENG":"No. The person I am looking for is not her.","TWN":"不是，我要找的另有其人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신들이 실패했던 성무 SI3E. 그 배후에 있었다고 추정되는 인물이죠.","JPN":"あなたたちが失敗した聖務SI3E。その背後にいたと推測される人物です。","ENG":"Who I am looking for is the person assumed to be behind Sacred Mission SI3E that your crew failed.","TWN":"我要找的，是聖務SI3E背後的主使者。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"배후라고? 대체 누가……!?","JPN":"背後だと？　いったい誰が……！？","ENG":"Behind? Who could have─?!","TWN":"背後的主使者？到底是誰……！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"분명, 당신도 아는 사람일 겁니다.","JPN":"きっと、あなたもご存じのはずです。","ENG":"I am certain that \\"he\\" is someone you know.","TWN":"那個人，你應該也認識。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"떠올려 보세요. 그 숲에서 당신을 구해 준 사람은 누구였죠?","JPN":"よく思い出してみてください。その森であなたを助けてくれた人は誰でしたか？","ENG":"Try to remember. Who was it that saved you from the forest?","TWN":"你試著回想一下，那時候在森林裡，是誰救你的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"구해 준 사람……?","JPN":"助けてくれた人……？","ENG":"Who saved me...?","TWN":"是誰救我的……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 넬슨이 잡혀가고, 숲 속에 혼자 남겨진 채 있었던 당신에게…….","JPN":"シスターネルソンが捕まり、森の中に一人残されていたあなたに……","ENG":"After Sister Nelson got kidnapped, you were all alone in that forest...","TWN":"尼爾森姊妹被抓走後，只剩你獨自留在森林裡時……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"구원의 손길을 내미는 척 하면서, 성황청의 눈을 피해 달아나라고 조언했던 자가 있었을 겁니다.","JPN":"救いの手を差し伸べるふりをしながら、聖皇庁の目を盗み逃げろと助言した者がいたはずです。","ENG":"But there must have been someone who approached you with malice, and advised you to hide from the Holy Curia.","TWN":"是誰假意向你伸出援手，並且建議你避開聖皇廳的耳目逃走的？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"말도 안 돼……. 그 신부님이……?","JPN":"そんな……あの神父様が……？","ENG":"It can't be... The Priest...?","TWN":"這怎麼可能……是那個神父……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그자의 이름은 <color=#ffd34c>베네딕트 콘스탄틴</color>.","JPN":"その男の名は<color=#ffd34c>ベネディクト・コンスタンティン</color>。","ENG":"His name is <color=#ffd34c>Benedict Constantine</color>.","TWN":"他的名字叫<color=#ffd34c>本尼迪克特·康斯坦丁</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청에서 수배 중인 1급 범죄자이자……","JPN":"聖皇庁で手配中の第1級犯罪者であり……","ENG":"A first-degree criminal wanted by the Holy Curia...","TWN":"是聖皇廳通緝的重犯……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"망집에 사로잡혀 용서받지 못할 죄를 저지른 광신도입니다.","JPN":"妄執にとらわれ、許されない罪を犯した狂信者です。","ENG":"And an unforgivable fanatic, engrossed in his twisted obsession, who has committed the most heinous of sins.","TWN":"他是走火入魔犯下重罪的極端分子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 이야기를 읽게 해 주셔서 감사합니다, 클락 헤밍턴 형제.","JPN":"あなたの物語を読ませていただきありがとうございます、クラーク・ハミントン兄弟。","ENG":"Thank you for letting me read your story, Brother Clark Hammington.","TWN":"克拉克·海明頓弟兄，謝謝你告訴我你的故事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 약속한 대로 당신의 고해성사를 도와드리도록 하죠.","JPN":"それでは、約束どおり告解をお手伝いいたしましょう。","ENG":"Then, as promised. I will assist you with your confession.","TWN":"我會照約定幫你告解。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"This is...?","TWN":"這是……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 넬슨이 입원 중인 병실의 주소입니다.","JPN":"シスターネルソンが入院している病室の住所です。","ENG":"This is the address to the hospital room where Sister Nelson is hospitalized.","TWN":"這是尼爾森姊妹住院的醫院地址。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"네, 넬슨 수녀님? 그 분이 살아 계셨다고……?","JPN":"し、シスターネルソン？　生きていらした……？","ENG":"S-sister Nelson? You mean she's alive...?","TWN":"尼…尼爾森修女？她還活著……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네. 거룩한 보살핌으로 생명에 지장은 없는 상태입니다.","JPN":"はい。聖なる加護のおかげで命に別条はない状態です。","ENG":"Yes. Thanks to divine care, she will continue to live.","TWN":"是，感謝天主，她目前沒有生命危險。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"늦지 않게 찾아가 보세요. 시스터는 분명 당신의 이야기를 들어줄 겁니다.","JPN":"遅くならないうちに訪ねてみてください。シスターはきっとあなたの物語を聞いてくれるはずです。","ENG":"Try to visit her soon. I am sure she will listen to your story.","TWN":"趕快去見她吧，她一定很樂意聽你說話的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"……가, 감사합니다!! 정말로 감사합니다!!","JPN":"……あ、ありがとうございます！！　本当にありがとうございます！！","ENG":"Th-thank you...! I can't thank you enough!!","TWN":"……謝…謝謝！！真的很謝謝你！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저에게 감사하실 것 없습니다, 헤밍턴 형제.","JPN":"私に感謝する必要はありません、ハミントン兄弟。","ENG":"There is no need to thank me, Brother Hammington.","TWN":"海明頓弟兄，你無須謝我。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"감사는 제가 아니라, 당신이 그동안 구해 낸 어린 양들에게 직접 전하도록 하세요.","JPN":"感謝は私にではなく、あなたがこれまで救ってきた子羊に直接伝えてください。","ENG":"It is not me you should be thanking, but the lambs you helped save during your time.","TWN":"你該謝的，是過去那些被你拯救過的小羊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};